VALUES
  ('judicial-57112235-moex-00147', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法有明文規定，監獄當局於適當時機應「通知家屬」之情形，下列敘述何者錯誤？', '["監獄施以隔離保護後，除應以書面告知受刑人外，應通知家屬或最近親屬，並安排醫事人持續評估 其身心狀況", "監獄人員於使用法務部核定之棍、刀、槍及其他器械為必要處置後，除應以書面告知受刑人外，應 通知家屬或最近親屬", "釋放衰老、重病、身心障礙不能自理生活之受刑人前，應通知家屬或受刑人認為適當之人來監接回", "受刑人於執行中死亡，監獄應即通知家屬或最近親屬，並逕報檢察署指派檢察官相驗"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00148', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '依司法院釋字第 777 號，關於刑法第 185 條之4 肇事逃逸罪，其中有關「肇事」部分，違反下列何項原 則？', '["罪刑相當原則", "法律保留原則", "罪疑惟輕原則", "法律明確性原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00149', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關刑法地之效力，下列敘述何者正確？', '["犯罪之結果在我國領域內者，適用我國刑法", "犯罪行為與結果皆在我國領域內者，始適用我國刑法", "外國人於我國領域內犯罪，不適用我國刑法", "外國人於我國領域外對於我國人民犯罪，一律不適用我國刑法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00150', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關刑法就犯罪成立之要件，於行為後法律有變更時，採取何種原則？', '["從舊原則", "從新原則", "從重原則", "從舊從輕原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00151', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何種事實係屬行為人故意必須認知的對象？', '["客觀構成要件", "客觀處罰條件", "量刑條件", "追訴條件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00152', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列何者非屬阻卻違法事由？', '["瘖啞人之行為", "依法令之行為", "業務上之正當行為", "正當防衛之行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00153', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '有關被害人承諾之敘述，下列何者正確？', '["被害人承諾為法定阻卻違法事由", "被害人承諾所放棄之法益，不包含生命法益、各種程度的身體健康法益", "國家法益、社會法益不在被害人承諾所得處分的範圍之內", "被害人需滿20歲，其所為之承諾方屬有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00154', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲的女友A另結新歡而向甲提議分手。甲憤恨不已，決定與A同歸於盡，因而開車前往A的住處。途中 甲一路盤算著要如何進行，開車不慎撞到某行人，當場撞死。甲趕緊下車察看，赫然發現竟是A。甲應如 何論罪？', '["故意殺人罪", "遺棄罪", "不能安全駕駛罪", "過失致死罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00155', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '甲患有思覺失調症，某日發病時毆打乙成傷，經精神科醫師鑑定後，甲行為當時已完全喪失辨識其行為違 法之判斷能力。有關甲之敘述，下列何者正確？', '["甲為無責任能力人", "甲為限制責任能力人", "甲為瘖啞人", "甲為完全責任能力人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00156', 'judicial-57112235', 'judicial-57112235-moex-113-e2754278', 'sub-judicial-57112235-01', NULL, 'single_choice', '下列犯罪，何者有處罰過失犯？', '["公務員洩漏國防以外之秘密罪（刑法第132條）", "強制性交罪（刑法第221條）", "毀損罪（刑法第354條）", "肇事逃逸罪（刑法第185條之4）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "205", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
